#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // GROW EFFECT - bright pixels spread radially outward.
    // BE CAREFUL - this can really thrash the texture cache! (SLOW)
    float grad_rad = 8;  //TWEAK
    float str = 4;      //TWEAK
    vec3 d = vec3(uTexSize.zw, 0) * grad_rad;
    vec4 lums = 0;
    lums.x = lum( MyGet(vUv + uTexSize.zw*d.xz) );
    lums.y = lum( MyGet(vUv - uTexSize.zw*d.xz) );
    lums.z = lum( MyGet(vUv + uTexSize.zw*d.zy) );
    lums.w = lum( MyGet(vUv - uTexSize.zw*d.zy) );
    vec2 grad = vec2(lums.x-lums.y, lums.z-lums.w)*str*1000/grad_rad;
    grad = (clamp01(grad*0.5+0.5)*2-1)*1.4;

    // sample previous uFrame
    ret = texture( sampler_fc_main, vUv + grad*uTexSize.zw ).xyz;

vec2 uv_echo = (vUv - 0.5)*vec2(-1,-1) + 0.5;

    vec4 lums2 = 0;
    lums2.x = lum( MyGet(uv_echo + uTexSize.zw*d.xz) );
    lums2.y = lum( MyGet(uv_echo - uTexSize.zw*d.xz) );
    lums2.z = lum( MyGet(uv_echo + uTexSize.zw*d.zy) );
    lums2.w = lum( MyGet(uv_echo - uTexSize.zw*d.zy) );
    vec2 grad2 = vec2(lums2.x-lums2.y, lums2.z-lums2.w)*str*1000/grad_rad;
    grad2 = (clamp01(grad2*0.5+0.5)*2-1)*1.4;

vec3 ret2 = texture(sampler_fc_main, uv_echo + grad2*uTexSize.zw).xyz;

ret = mix(ret,ret2,0.50);

    // darken (decay) over uTime
    ret *= 0.93; //or try: ret -= 0.004;

  fragColor = ret;
}

